1	<script lang="ts">
2		import type { PageData } from './$types'
3		import { page } from '$app/stores'
4		import { goto } from '$app/navigation'
5		import { createClient } from '$lib/gql/client'
6		import { PROJECT_RUNS_QUERY, PAGE_SIZE } from './+page'
7		import type { RunEdge, RunNode, RunConnection, PageInfo } from './+page'
8		import { RunRowDetail } from '$lib/runDetail'
9		import ConfirmDialog from '$lib/components/ConfirmDialog.svelte'
10		import FilterChip from '$lib/components/FilterChip.svelte'
11		import { RUN_REQUEUE_MUTATION, WORKER_DISPATCH_MUTATION } from '$lib/gql/feat008'
12	
13		// Threshold above which the runs table opts into browser-native row
14		// windowing via `content-visibility: auto`. Keeps DOM semantics, table
15		// layout, row expansion, and any future live worker phase subscriptions
16		// intact — the browser simply skips rendering off-screen rows.
17		const VIRTUALIZE_THRESHOLD = 1000
18		const VIRTUAL_ROW_HEIGHT_PX = 49
19	
20		let { data }: { data: PageData } = $props()
21	
22		let appendedEdges = $state<RunEdge[]>([])
23		let appendedPageInfo = $state<PageInfo | null>(null)
24		let loadingMore = $state(false)
25		let harnessInput = $state(data.activeHarness ?? '')
26		let expanded = $state<Set<string>>(new Set())
27	
28		type ActionMode = 'requeue' | 'startWorker'
29		let actionDialogOpen = $state(false)
30		let actionMode = $state<ActionMode>('requeue')
31		let actionRun = $state<RunNode | null>(null)
32		let actionIdempotencyKey = $state('')
33		let actionLayerOverride = $state('')
34		let actionWorkerArgs = $state('')
35		let actionAlert = $state('')
36		let actionResultMessage = $state('')
37	
38		function newIdempotencyKey(): string {
39			if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
40				return crypto.randomUUID()
41			}
42			return `requeue-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`
43		}
44	
45		function openRequeueDialog(run: RunNode) {
46			actionMode = 'requeue'
47			actionRun = run
48			actionIdempotencyKey = newIdempotencyKey()
49			actionLayerOverride = run.layer
50			actionAlert = ''
51			actionResultMessage = ''
52			actionDialogOpen = true
53		}
54	
55		function openStartWorkerDialog(run: RunNode) {
56			actionMode = 'startWorker'
57			actionRun = run
58			actionAlert = ''
59			actionResultMessage = ''
60			// Prefill the worker args with the original drain's queueInputs JSON.
61			// Pretty-print so the operator can review/edit before dispatching.
62			if (run.queueInputs) {
63				try {
64					actionWorkerArgs = JSON.stringify(JSON.parse(run.queueInputs), null, 2)
65				} catch {
66					actionWorkerArgs = run.queueInputs
67				}
68			} else {
69				actionWorkerArgs = JSON.stringify(
70					{ source: 'runs-start-worker', sourceRunId: run.id },
71					null,
72					2
73				)
74			}
75			actionDialogOpen = true
76		}
77	
78		async function confirmAction() {
79			if (!actionRun) return
80			const client = createClient()
81			try {
82				if (actionMode === 'requeue') {
83					if (!actionIdempotencyKey.trim()) {
84						actionAlert = 'Idempotency key is required.'
85						throw new Error('missing idempotency key')
86					}
87					const layer = actionLayerOverride.trim()
88					const result = await client.request<{
89						runRequeue: { bead: { id: string }; deduplicated: boolean }
90					}>(RUN_REQUEUE_MUTATION, {
91						input: {
92							runId: actionRun.id,
93							idempotencyKey: actionIdempotencyKey,
94							layer: layer ? layer : null
95						}
96					})
97					actionResultMessage = result.runRequeue.deduplicated
98						? `Bead ${result.runRequeue.bead.id} already requeued (deduplicated).`
99						: `Bead ${result.runRequeue.bead.id} requeued.`
100				} else {
101					// startWorker: validate JSON before sending so the operator can fix it inline.
102					let argsString = actionWorkerArgs.trim()
103					if (argsString) {
104						try {
105							JSON.parse(argsString)
106						} catch (err) {
107							actionAlert = `Worker args must be valid JSON: ${errorText(err)}`
108							throw err
109						}
110					} else {
111						argsString = '{}'
112					}
113					const projectId = actionRun.projectID ?? data.projectId
114					const result = await client.request<{
115						workerDispatch: { id: string; state: string; kind: string }
116					}>(WORKER_DISPATCH_MUTATION, {
117						kind: 'execute-loop',
118						projectId,
119						args: argsString
120					})
121					actionResultMessage = `Worker ${result.workerDispatch.id} started (${result.workerDispatch.state}).`
122				}
123			} catch (err) {
124				if (!actionAlert) actionAlert = errorText(err)
125				throw err
126			}
127		}
128	
129		function errorText(err: unknown): string {
130			if (err instanceof Error) return err.message
131			if (typeof err === 'string') return err
132			return 'Unknown error.'
133		}
134	
135		function toggleExpand(runId: string) {
136			const next = new Set(expanded)
137			if (next.has(runId)) next.delete(runId)
138			else next.add(runId)
139			expanded = next
140		}
141	
142		let filterKey = $derived(`${data.activeLayer}::${data.activeStatus}::${data.activeHarness}`)
143		let prevFilterKey = $state('')
144		$effect(() => {
145			if (filterKey !== prevFilterKey) {
146				prevFilterKey = filterKey
147				appendedEdges = []
148				appendedPageInfo = null
149			}
150		})
151	
152		let edges = $derived([...data.runs.edges, ...appendedEdges])
153		let pageInfo = $derived<PageInfo>(appendedPageInfo ?? data.runs.pageInfo)
154	
155		let virtualized = $derived(edges.length >= VIRTUALIZE_THRESHOLD)
156		let rowStyle = $derived(
157			virtualized
158				? `content-visibility: auto; contain-intrinsic-size: 0 ${VIRTUAL_ROW_HEIGHT_PX}px;`
159				: ''
160		)
161	
162		const LAYER_OPTIONS = ['work', 'try', 'run']
163		const STATUS_OPTIONS = ['pending', 'running', 'success', 'failure', 'preserved']
164	
165		function setFilter(key: 'layer' | 'status' | 'harness', value: string | null) {
166			const params = new URLSearchParams($page.url.searchParams)
167			if (value === null || value === '') {
168				params.delete(key)
169			} else {
170				params.set(key, value)
171			}
172			const search = params.toString()
173			goto(search ? `?${search}` : $page.url.pathname, { replaceState: false })
174		}
175	
176		function toggleLayer(layer: string) {
177			setFilter('layer', data.activeLayer === layer ? null : layer)
178		}
179	
180		function toggleStatus(status: string) {
181			setFilter('status', data.activeStatus === status ? null : status)
182		}
183	
184		function applyHarness() {
185			setFilter('harness', harnessInput.trim() || null)
186		}
187	
188		async function loadMore() {
189			if (!pageInfo.hasNextPage || loadingMore) return
190			loadingMore = true
191			try {
192				const client = createClient()
193				const result = await client.request<{ runs: RunConnection }>(PROJECT_RUNS_QUERY, {
194					projectID: data.projectId,
195					first: PAGE_SIZE,
196					after: pageInfo.endCursor,
197					layer: data.activeLayer ?? undefined,
198					status: data.activeStatus ?? undefined,
199					harness: data.activeHarness ?? undefined
200				})
201				appendedEdges = [...appendedEdges, ...result.runs.edges]
202				appendedPageInfo = result.runs.pageInfo
203			} finally {
204				loadingMore = false
205			}
206		}
207	
208		function runDetailHref(runId: string): string {
209			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${runId}`
210		}
211	
212		function beadHref(beadId: string): string {
213			return `/nodes/${data.nodeId}/projects/${data.projectId}/beads/${beadId}`
214		}
215	
216		function fmtDate(iso: string | null): string {
217			if (!iso) return '—'
218			return new Date(iso).toLocaleString()
219		}
220	
221		function fmtDuration(ms: number | null): string {
222			if (ms == null) return '—'
223			if (ms < 1000) return `${ms}ms`
224			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
225			const m = Math.floor(ms / 60_000)
226			const s = Math.floor((ms % 60_000) / 1000)
227			return `${m}m ${s}s`
228		}
229	
230		function layerBadgeClass(layer: string): string {
231			switch (layer) {
232				case 'work':
233					return 'badge-layer-work'
234				case 'try':
235					return 'badge-layer-try'
236				case 'run':
237					return 'badge-layer-run'
238				default:
239					return 'badge-status-neutral'
240			}
241		}
242	
243		function statusBadgeClass(status: string): string {
244			switch (status) {
245				case 'success':
246					return 'badge-status-closed'
247				case 'failure':
248					return 'badge-status-failed'
249				case 'running':
250					return 'badge-status-running'
251				case 'preserved':
252					return 'badge-status-in-progress'
253				default:
254					return 'badge-status-open'
255			}
256		}
257	
258	</script>
259	
260	<div class="space-y-4">
261		<div class="flex items-center justify-between">
262			<h1 class="text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink">Runs</h1>
263			<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
264				{edges.length} of {data.runs.totalCount}
265			</span>
266		</div>
267	
268		<!-- Layer filter chips -->
269		<div class="flex flex-wrap gap-2" data-testid="layer-chips">
270			<span class="self-center font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted">Layer</span>
271			{#each LAYER_OPTIONS as layer}
272				<FilterChip
273					label={layer}
274					testid="layer-chip-{layer}"
275					active={data.activeLayer === layer}
276					ariaPressed={data.activeLayer === layer}
277					onclick={() => toggleLayer(layer)}
278				/>
279			{/each}
280			{#if data.activeLayer}
281				<FilterChip
282					label="Clear"
283					testid="layer-chip-clear"
284					clear
285					onclick={() => setFilter('layer', null)}
286				/>
287			{/if}
288		</div>
289	
290		<!-- Status filter chips -->
291		<div class="flex flex-wrap gap-2" data-testid="status-chips">
292			<span class="self-center font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted">Status</span>
293			{#each STATUS_OPTIONS as status}
294				<FilterChip
295					label={status}
296					testid="status-chip-{status}"
297					active={data.activeStatus === status}
298					ariaPressed={data.activeStatus === status}
299					onclick={() => toggleStatus(status)}
300				/>
301			{/each}
302			{#if data.activeStatus}
303				<FilterChip
304					label="Clear"
305					testid="status-chip-clear"
306					clear
307					onclick={() => setFilter('status', null)}
308				/>
309			{/if}
310		</div>
311	
312		<!-- Harness filter -->
313		<form
314			class="flex items-center gap-2"
315			onsubmit={(e) => {
316				e.preventDefault()
317				applyHarness()
318			}}
319		>
320			<span class="text-xs text-fg-muted dark:text-dark-fg-muted">Harness:</span>
321			<input
322				type="text"
323				bind:value={harnessInput}
324				placeholder="claude / codex / agent"
325				class="w-44 border border-border-line bg-bg-elevated px-2 py-1 font-mono-code text-mono-code text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
326			/>
327			<button
328				type="submit"
329				class="border border-border-line bg-bg-elevated px-2 py-1 text-xs text-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
330			>
331				Apply
332			</button>
333			{#if data.activeHarness}
334				<button
335					type="button"
336					onclick={() => {
337						harnessInput = ''
338						setFilter('harness', null)
339					}}
340					class="border border-border-line bg-bg-elevated px-2 py-1 text-xs text-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
341				>
342					Clear
343				</button>
344			{/if}
345		</form>
346	
347		<div
348			class="overflow-hidden border border-border-line dark:border-dark-border-line"
349			data-testid="runs-table"
350			data-virtualized={virtualized ? 'true' : 'false'}
351		>
352			<table class="w-full text-sm">
353				<thead>
354					<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
355						<th class="w-6 px-4 py-3"></th>
356						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Layer</th>
357						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Status</th>
358						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Bead</th>
359						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Harness</th>
360						<th class="px-4 py-3 text-left font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Started</th>
361						<th class="px-4 py-3 text-right font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Duration</th>
362						<th class="px-4 py-3 text-right font-label-caps text-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Actions</th>
363					</tr>
364				</thead>
365				<tbody>
366					{#each edges as edge (edge.cursor)}
367						{@const isExpanded = expanded.has(edge.node.id)}
368						<tr
369							class="cursor-pointer border-b border-border-line last:border-0 hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface {isExpanded
370								? 'bg-accent-lever/10 dark:bg-dark-accent-lever/10'
371								: ''}"
372							data-run-row={edge.node.id}
373							style={rowStyle}
374							onclick={() => toggleExpand(edge.node.id)}
375						>
376							<td class="px-4 py-3 text-body-sm text-fg-muted dark:text-dark-fg-muted">
377								{isExpanded ? '▾' : '▸'}
378							</td>
379							<td class="px-4 py-3">
380								<span class="inline-block rounded-full px-2 py-0.5 font-label-caps text-label-caps uppercase {layerBadgeClass(edge.node.layer)}">
381									{edge.node.layer}
382								</span>
383							</td>
384							<td class="px-4 py-3">
385								<span class="inline-block border px-1.5 py-0.5 font-mono-code text-mono-code uppercase {statusBadgeClass(edge.node.status)}">
386									{edge.node.status}
387								</span>
388							</td>
389							<td class="px-4 py-3">
390								{#if edge.node.beadId}
391									<a
392										href={beadHref(edge.node.beadId)}
393										onclick={(e) => e.stopPropagation()}
394										class="font-mono-code text-mono-code text-accent-lever hover:underline dark:text-dark-accent-lever"
395									>
396										{edge.node.beadId}
397									</a>
398								{:else}
399									<span class="text-fg-muted dark:text-dark-fg-muted">—</span>
400								{/if}
401							</td>
402							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
403								{edge.node.harness ?? '—'}
404							</td>
405							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
406								{fmtDate(edge.node.startedAt)}
407							</td>
408							<td class="px-4 py-3 text-right font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
409								<div class="flex items-center justify-end gap-2">
410									<span>{fmtDuration(edge.node.durationMs)}</span>
411									<a
412										href={runDetailHref(edge.node.id)}
413										onclick={(e) => e.stopPropagation()}
414										title="Open detail page"
415										class="font-mono-code text-mono-code text-accent-lever hover:underline dark:text-dark-accent-lever"
416									>
417										↗
418									</a>
419								</div>
420							</td>
421							<td class="px-4 py-3 text-right">
422								{#if edge.node.layer === 'work'}
423									<button
424										type="button"
425										data-run-action="start-worker"
426										data-run-id={edge.node.id}
427										onclick={(e) => {
428											e.stopPropagation()
429											openStartWorkerDialog(edge.node)
430										}}
431										class="rounded-sm border border-border-line bg-bg-elevated px-2 py-1 text-xs font-medium text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
432									>
433										Start worker
434									</button>
435								{:else}
436									<button
437										type="button"
438										data-run-action="requeue"
439										data-run-id={edge.node.id}
440										onclick={(e) => {
441											e.stopPropagation()
442											openRequeueDialog(edge.node)
443										}}
444										class="rounded-sm border border-border-line bg-bg-elevated px-2 py-1 text-xs font-medium text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
445									>
446										Re-queue
447									</button>
448								{/if}
449							</td>
450						</tr>
451						{#if isExpanded}
