468							</td>
469						</tr>
470					{/if}
471				</tbody>
472			</table>
473		</div>
474	
475		{#if actionResultMessage}
476			<div
477				role="status"
478				class="rounded-md border border-accent-fulcrum/30 bg-accent-fulcrum/10 px-4 py-2 text-sm text-fg-ink dark:border-dark-accent-fulcrum/30 dark:bg-dark-accent-fulcrum/10 dark:text-dark-fg-ink"
479				data-run-action-result
480			>
481				{actionResultMessage}
482			</div>
483		{/if}
484	
485		{#if pageInfo.hasNextPage}
