491				>
492					{loadingMore ? 'Loading…' : 'Load more'}
493				</button>
494			</div>
495		{/if}
496	</div>
497	
498	<ConfirmDialog
499		bind:open={actionDialogOpen}
500		title={actionMode === 'requeue' ? 'Re-queue run' : 'Start worker from this drain'}
501		actionLabel={actionMode === 'requeue' ? 'Re-queue' : 'Start worker'}
502		onConfirm={confirmAction}
503	>
504		{#snippet summary()}
505			<span>
506				{#if actionRun}
507					{actionMode === 'requeue'
508						? `Re-queue ${actionRun.layer} run ${actionRun.id}`
