510				{/if}
511			</span>
512		{/snippet}
513	
514		{#if actionRun}
515			<div class="space-y-3">
516				{#if actionAlert}
517					<div
518						role="alert"
519						class="rounded border border-error/30 bg-error/10 px-3 py-2 text-xs text-error dark:border-dark-error/30 dark:bg-dark-error/10 dark:text-dark-error"
520						data-run-action-alert
521					>
522						{actionAlert}
523					</div>
524				{/if}
525	
526				{#if actionMode === 'requeue'}
527					<div>
528						<label class="mb-1 block font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted" for="requeue-run-id">
529							Run ID
530						</label>
531						<input
532							id="requeue-run-id"
533							type="text"
534							readonly
535							value={actionRun.id}
536							class="w-full border border-border-line bg-bg-surface px-2 py-1 font-mono-code text-mono-code text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink"
537						/>
538					</div>
539					<div>
540						<label class="mb-1 block font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted" for="requeue-layer">
541							Layer override
542						</label>
543						<select
